import { writeFile } from "node:fs/promises";
import { resolve } from "node:path";
import { fetchSubstackPosts } from "./substack-feed.mjs";

const OUTPUT_FILE = resolve(process.cwd(), "src/data/blogPosts.ts");

function toModuleSource(posts) {
  return `export type BlogPost = {
  title: string;
  slug: string;
  excerpt: string;
  publishedAt: string;
  author: string;
  sourceUrl: string;
  image: string | null;
  contentHtml: string;
  featured?: boolean;
  tag?: string;
};

// Generated by scripts/sync-substack.mjs
export const blogPosts: BlogPost[] = ${JSON.stringify(posts, null, 2)} as BlogPost[];
`;
}

async function main() {
  const posts = await fetchSubstackPosts();

  await writeFile(OUTPUT_FILE, toModuleSource(posts));
  console.log(`Synced ${posts.length} Substack post(s) to ${OUTPUT_FILE}`);
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
